const body   = $input.first().json.body || $input.first().json;
const platform = (body.target_platform || 'Moltcorp').trim();
const taskType = body.task_type   || 'general';
const rawData  = body.raw_data    || {};
const context  = body.context     || '';
const dataStr  = typeof rawData === 'string' ? rawData : JSON.stringify(rawData, null, 2);

let deepseekPrompt, qwenPrompt, kimiPrompt;

if (platform === 'Numerai') {
  deepseekPrompt = [
    'You are a Quantitative Auditor for Numerai (https://numer.ai/).',
    'Review the XGBoost/ML parameter set below for overfitting risks against the v5.0/live.parquet dataset.',
    'Output a structured critique: risk_level (low/medium/high), mmc_impact, recommended_changes.',
    '', `Context: ${context}`, '', `Data:`, dataStr
  ].join('\n');

  qwenPrompt = [
    'You are a Python Feature Engineering Agent for Numerai.',
    'Analyze the feature importance list and suggest exactly 3 new feature engineering techniques',
    'optimised for financial time-series obfuscation. Output as numbered list with code snippets.',
    '', `Context: ${context}`, '', `Data:`, dataStr
  ].join('\n');

  kimiPrompt = [
    'ORIA: You are a Deep-Context Meta-Analyst for Numerai tournament strategy.',
    'Cross-reference this strategy with current market volatility patterns and tournament rules.',
    'Goal: maximise NMR staking yield and Meta-Model Contribution (MMC).',
    '', `Context: ${context}`, '', `Data:`, dataStr,
    '/ORI'
  ].join('\n');

} else {
  // Default: Moltcorp / Apex PR audit
  const diff = rawData.raw_code_diff || dataStr;
  const scan = rawData.superz_initial_scan || '';

  deepseekPrompt = [
    'You are a Security Auditor performing a hard-review of this code diff.',
    'Check for: authentication bypasses, payment gateway friction, injection vectors, logic errors.',
    'Output format: VERDICT: PASS or FAIL, then FINDINGS: (numbered list), SEVERITY: critical/high/medium/low.',
    '', `Context: ${context}`, '', 'Code Diff:', diff,
    scan ? `\nSuperZ Scan: ${scan}` : ''
  ].join('\n');

  qwenPrompt = [
    'You are a Senior Software Architect reviewing this PR for the Apex fintech platform.',
    'Check: performance bottlenecks, redundant loops, clean-code violations, TypeScript type safety.',
    'Output: CODE_QUALITY_SCORE: X/10, ISSUES: (list), REWRITES: (show improved snippets).',
    '', `Context: ${context}`, '', 'Code Diff:', diff,
    scan ? `\nSuperZ Scan: ${scan}` : ''
  ].join('\n');

  kimiPrompt = [
    'ORIA: You are a UX/Product Designer for the Apex "African Futurism" platform.',
    'Review this PR from the end-user perspective. Does it break the visual language, UTM tracking, or payment flow?',
    'Output: UX_IMPACT: low/medium/high, BREAKING_CHANGES: yes/no, RECOMMENDATIONS: (list).',
    '', `Context: ${context}`, '', 'Code Diff:', diff,
    scan ? `\nSuperZ Scan: ${scan}` : '',
    '/ORI'
  ].join('\n');
}

return [{ json: { deepseek_prompt: deepseekPrompt, qwen_prompt: qwenPrompt,
  kimi_prompt: kimiPrompt, target_platform: platform, task_type: taskType, context } }];

const items = $input.all();
return items.map((item, i) => {
  const models = [
    { id: 'deepseek-r1', label: 'DeepSeek-R1 (Reasoning)', inputPort: 0 },
    { id: 'qwen3.5',     label: 'Qwen3.5 (Analysis)',       inputPort: 1 },
    { id: 'kimi-k2',     label: 'Kimi K2 (Thinking)',       inputPort: 2 },
  ];
  const raw = item.json.response || item.json.message?.content || '[no response]';
  const cleaned = raw.replace(/ORIA[\s\S]*?<\/ORI>/gi, '').trim();
  const timedOut = raw === '[no response]' || cleaned.length < 10;
  return { json: {
    model_id:       models[i]?.id    || `model_${i}`,
    model_label:    models[i]?.label || `Model ${i}`,
    raw_response:   raw,
    response:       cleaned,
    word_count:     cleaned.split(/\s+/).length,
    timed_out:      timedOut,
    eval_count:     item.json.eval_count     || 0,
    duration_ms:    Math.round((item.json.total_duration || 0) / 1e6),
  }};
});

const items       = $input.all();
const platform    = $('Prepare Prompts').item.json.target_platform || 'Moltcorp';
const allTimedOut = items.every(i => i.json.timed_out);

// ── Fallback: all models failed ─────────────────────────────────────────────
if (allTimedOut) {
  // Log the error for trace analysis
  console.error('All 3 models timed out. Falling back to safe default.');
  return [{ json: {
    best_model:    'fallback',
    best_label:    'Fallback (Safe Default)',
    best_response: 'All 3 models timed out. Manual review required before proceeding.',
    best_score:    0,
    hard_fail:     false,
    fallback_used: true,
    all_responses: items.map(i => ({ model: i.json.model_id, score: 0, timed_out: true })),
    timestamp:     new Date().toISOString(),
  }}];
}

// ── Scoring weights (per spec) ───────────────────────────────────────────────
// Synthesis: (Qwen_Code * 0.4) + (DeepSeek_Logic * 0.4) + (Kimi_UX * 0.2)
const scored = items.map(item => {
  const { model_id, response, word_count, timed_out } = item.json;
  if (timed_out) return { ...item.json, score: 0, hard_fail: false };

  const text = response.toLowerCase();
  let score = 0;
  let hardFail = false;

  if (model_id === 'deepseek-r1') {
    // Logic/security weight: 0.4
    const hasFail = text.includes('fail') || text.includes('verdict: fail');
    if (hasFail) { hardFail = true; score = 100 * 0.4; } // Hard fail is definitive
    else { score = (text.includes('pass') ? 80 : 60) * 0.4; }
    if (text.includes('critical')) score += 10 * 0.4;
    if (text.includes('vulnerability')) score += 10 * 0.4;

  } else if (model_id === 'qwen3.5') {
    // Code quality weight: 0.4
    const match = text.match(/code_quality_score[:\s]+(\d+)/);
    const qualityScore = match ? parseInt(match[1]) : Math.min(word_count / 20, 10);
    score = qualityScore * 8 * 0.4;
    if (text.includes('optimization') || text.includes('optimise')) score += 10 * 0.4;

  } else if (model_id === 'kimi-k2') {
    // UX impact weight: 0.2
    const impactMap = { low: 30, medium: 60, high: 90 };
    const match = text.match(/ux_impact[:\s]+(low|medium|high)/);
    const impact = match ? impactMap[match[1]] : 50;
    score = impact * 0.2;
    if (text.includes('breaking_changes: no') || text.includes('no breaking')) score += 10 * 0.2;
  }

  return { ...item.json, score: Math.round(score * 10) / 10, hard_fail: hardFail };
});

// ── Hard fail gate: DeepSeek said FAIL → reject immediately ─────────────────
const deepseekResult = scored.find(s => s.model_id === 'deepseek-r1');
const hardFail = deepseekResult?.hard_fail === true;

// ── Pick winner ─────────────────────────────────────────────────────────────
const best = scored.reduce((prev, curr) => curr.score > prev.score ? curr : prev);

return [{ json: {
  best_model:    best.model_id,
  best_label:    best.model_label,
  best_response: best.response,
  best_score:    best.score,
  hard_fail,
  fallback_used: false,
  platform,
  all_responses: scored.map(s => ({
    model: s.model_label, score: s.score, words: s.word_count,
    duration_ms: s.duration_ms, timed_out: s.timed_out
  })),
  timestamp: new Date().toISOString(),
}}];
